from flask import Flask, request
from prometheus_client import Counter, make_wsgi_app
from werkzeug.middleware.dispatcher import DispatcherMiddleware
import re

app = Flask(__name__)

# Define a regex pattern for validating user_id and session_id
USER_ID_PATTERN = re.compile(r'^[a-zA-Z0-9_-]{1,30}$')
SESSION_ID_PATTERN = re.compile(r'^[a-zA-Z0-9_-]{1,30}$')

# Dictionary to hold metrics for unique user-path combinations
metrics = {}

def validate_input(user_id, session_id):
    return USER_ID_PATTERN.match(user_id) and SESSION_ID_PATTERN.match(session_id)

@app.route('/<path:full_path>', methods=['GET', 'POST'])
def track_request():
    user_id = request.headers.get('X-User-ID')
    session_id = request.headers.get('X-Session-ID')

    if not validate_input(user_id, session_id):
        return "Invalid user_id or session_id", 400

    metric_key = f"{user_id}_{full_path}"
    if metric_key not in metrics:
        metrics[metric_key] = Counter('http_requests_total', 'Total HTTP Requests', ['user_id', 'full_path'])
    
    metrics[metric_key].labels(user_id=user_id, full_path=full_path).inc()
    
    return "Request tracked", 200

app.wsgi_app = DispatcherMiddleware(app.wsgi_app, {
    '/metrics': make_wsgi_app()
})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)